.darma-loader-darma-custom-550 {color: var(--loader-color, #16a34a);
   width: 60px;
   height: 16px;
   display: grid;
}
.darma-loader-darma-custom-550:before, .darma-loader-darma-custom-550:after  {
  content: "";
   grid-area: 1/1;
   --c:no-repeat linear-gradient(var(--loader-color, #16a34a) 0 0);
   background: var(--c), var(--c), var(--c);
   animation: darma-loader-darma-custom-550-l16-1 1.5s infinite linear, darma-loader-darma-custom-550-l16-2 1.5s infinite linear;
   transform: scale(var(--s,1)) translate(3px,-3px);
}
.darma-loader-darma-custom-550:after  {
  --s:-1;
}
@keyframes darma-loader-darma-custom-550-l16-1  {
  0%, 3% {background-size: 0 4px,4px 0 ,0 4px}
16.67%{background-size: 100% 4px,4px 0 ,0 4px}
33.33%{background-size: 100% 4px,4px 100%,0 4px}
46%, 54% {background-size: 100% 4px,4px 100%,100% 4px}
66.67%{background-size: 0 4px,4px 100%,100% 4px}
83.33%{background-size: 0 4px,4px 0 ,100% 4px}
96%, 100% {background-size: 0 4px,4px 0 ,0 4px}
}
@keyframes darma-loader-darma-custom-550-l16-2  {
  0%,49.9%{background-position: 0 0,100% 0 ,100% 100%}
50%,100%{background-position: 100% 0,100% 100%,0 100%}
}

